#!/usr/bin/env python3
"""Check the actual eval_config.json format."""
import json
import os
import glob

# Check /data directory
print('Files in /data:')
for f in sorted(os.listdir('/data')):
    print(f'  {f}')

# Check eval_config.json
for path in ['/data/eval_config.json', '/data/maps_eval/eval_config.json']:
    if os.path.exists(path):
        print(f'\nFound: {path}')
        with open(path) as f:
            config = json.load(f)
        print(f'Keys: {list(config.keys())}')
        print(f'Content (first 500 chars): {json.dumps(config, indent=2)[:500]}')

# Check maps_eval directory
if os.path.exists('/data/maps_eval'):
    print('\nFiles in /data/maps_eval:')
    for f in sorted(os.listdir('/data/maps_eval')):
        print(f'  {f}')
    for env_type in ['room', 'tunnel', 'outdoor']:
        d = f'/data/maps_eval/{env_type}'
        if os.path.exists(d):
            maps = glob.glob(f'{d}/*.png')
            print(f'  {env_type}: {len(maps)} maps')
            if maps:
                print(f'    example: {maps[0]}')
